import { Link } from "react-router-dom";
import { useParams } from 'react-router-dom';
import data from './../data-json/bebidas.json';

function TarjetaAmpliada() {

    const { id } = useParams();
    const item = data.find(i => i.id === id);

    if (!item) return <div>Producto no encontrado</div>;



    return (
        <div class="tarjeta-ampliada" key={data.id}>
            <img src={data.img} alt={data.titulo} />
            <div class="t-a-tarjeta-cont">
                <div class="t-a-texto-tarjeta">
                    <h3>{data.titulo}</h3>
                    <p>{data.precio}</p>
                    <p>{data.descripcion}</p>
                </div>
                <div class="t-a-button-cont">
                    <button><Link to={`/Productos`}>Ver Menos...</Link></button>
                    <button><img src="/add-carrito.svg" alt="Carrito" /></button>
                </div>
            </div>
        </div>
    )
}

export default TarjetaAmpliada;
